// ============================================
// IMPORTAÇÕES
// ============================================
const express = require('express');
const mysql = require('mysql2/promise');
const cors = require('cors');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');
const multer = require('multer');
const path = require('path');

const app = express();

// ============================================
// CONFIG
// ============================================
const PORT = 3001;
const SECRET = 'segredo_super_forte';

// ============================================
// MIDDLEWARES
// ============================================
app.use(cors());
app.use(express.json());
app.use('/uploads', express.static('uploads'));

// ============================================
// CONFIGURAÇÃO DE UPLOAD (CORRETA)
// ============================================
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, 'uploads/');
  },
  filename: (req, file, cb) => {
    cb(null, Date.now() + path.extname(file.originalname));
  }
});

const upload = multer({ storage });

// ============================================
// BANCO
// ============================================
const pool = mysql.createPool({
  host: 'localhost',
  user: 'root',
  password: '123456',
  database: 'nps_system'
});

// ============================================
// TESTE
// ============================================
app.get('/', (req, res) => {
  res.send('API funcionando 🚀');
});

// ============================================
// CLINICS
// ============================================
app.get('/clinics', async (req, res) => {
  try {
    const [rows] = await pool.query('SELECT * FROM clinics');
    res.json(rows);
  } catch (error) {
    console.error(error);
    res.status(500).json({ error: 'Erro ao buscar clínicas' });
  }
});

// ============================================
// LOGIN
// ============================================
app.post('/login', async (req, res) => {
  try {
    const { email, password } = req.body;

    const [rows] = await pool.query(
      'SELECT * FROM users WHERE email = ?',
      [email]
    );

    if (rows.length === 0) {
      return res.status(401).json({ message: 'Usuário não encontrado' });
    }

    const user = rows[0];
    const validPassword = await bcrypt.compare(password, user.password);

    if (!validPassword) {
      return res.status(401).json({ message: 'Senha inválida' });
    }

    const token = jwt.sign({ id: user.id }, SECRET);

    res.json({ message: 'Login ok', token });

  } catch (error) {
    console.error(error);
    res.status(500).json({ error: 'Erro no login' });
  }
});

// ============================================
// NPS
// ============================================
app.post('/nps', async (req, res) => {
  try {
    const { clinic_id, patient_name, score, comment } = req.body;

    await pool.query(
      'INSERT INTO nps_responses (clinic_id, patient_name, score, comment) VALUES (?, ?, ?, ?)',
      [clinic_id, patient_name, score, comment]
    );

    res.json({ message: 'NPS salvo com sucesso' });

  } catch (error) {
    console.error(error);
    res.status(500).json({ error: 'Erro ao salvar NPS' });
  }
});

// ============================================
// CALCULAR NPS
// ============================================
app.get('/nps/score', async (req, res) => {
  try {
    const [rows] = await pool.query('SELECT score FROM nps_responses');

    let promoters = 0;
    let detractors = 0;

    rows.forEach(r => {
      if (r.score >= 9) promoters++;
      else if (r.score <= 6) detractors++;
    });

    const total = rows.length;
    const nps = total > 0 ? ((promoters - detractors) / total) * 100 : 0;

    res.json({ total, promoters, detractors, nps });

  } catch (error) {
    console.error(error);
    res.status(500).json({ error: 'Erro ao calcular NPS' });
  }
});

// ============================================
// LISTAR RECLAMAÇÕES
// ============================================
app.get('/complaints', async (req, res) => {
  try {
    const [rows] = await pool.query('SELECT * FROM complaints');
    res.json(rows);
  } catch (error) {
    console.error(error);
    res.status(500).json({ error: 'Erro ao buscar reclamações' });
  }
});

// ============================================
// CRIAR RECLAMAÇÃO (COM UPLOAD)
// ============================================
app.post('/complaints', upload.single('file'), async (req, res) => {
  try {
    const {
      clinic_id,
      patient_name,
      patient_phone,
      channel,
      description,
      service_type
    } = req.body;

    const file_url = req.file
      ? `http://localhost:3001/uploads/${req.file.filename}`
      : null;

    const [result] = await pool.query(
      `INSERT INTO complaints 
      (clinic_id, patient_name, patient_phone, channel, description, service_type, attachment_url, status)
      VALUES (?, ?, ?, ?, ?, ?, ?, 'aberta')`,
      [
        clinic_id,
        patient_name,
        patient_phone,
        channel,
        description,
        service_type,
        file_url
      ]
    );

    res.json({
      message: 'Reclamação salva com sucesso',
      id: result.insertId
    });

  } catch (error) {
    console.error("ERRO:", error);
    res.status(500).json({ error: 'Erro ao salvar reclamação' });
  }
});

// ============================================
// START
// ============================================
app.listen(PORT, () => {
  console.log(`🚀 Servidor rodando em http://localhost:${PORT}`);
});
app.post('/login', (req, res) => {
  const { email, password } = req.body;

  // 🔒 SIMPLES (depois melhoramos)
  if (email === 'admin@sorria.com' && password === '123456') {
    return res.json({ token: '123' });
  }

  res.status(401).json({ error: 'Login inválido' });
});
